mapper.select:
SELECT item_id, session_id, content, category, sort_order, created_at, updated_at
FROM decompression_item
WHERE item_id = #{itemId}

mapper.update:
UPDATE decompression_item
SET category = #{category}
WHERE item_id = #{itemId}

mapper.select:
SELECT MAX(sort_order)
FROM decompression_item
WHERE session_id = #{sessionId}
